window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["i"]={"Igor": "<b>Igor</b> – zaimportowane z Rosji <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>, wywodzące się z pierwotnego <b><a href=\"https://pl.wikipedia.org/wiki/Ingwar\" target=\"_blank\" rel=\"noopener noreferrer\">Ingwar</a></b> (<i>Ingvarr</i>). Imię to jest złożone z członów: <i>Ing-</i>, prawdopodobnie pochodzącego od imienia jednego z bogów germańskich, oraz <i>-war</i>, pochodzącego najprawdopodobniej od staro-wysoko-niemieckiego słowa <i>wart</i> – <i><b>stróż</b></i>, <i><b>pasterz</b></i>. Imię to nosił wielki książę kijowski i czernihowski z <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII</a> wieku <a href=\"https://pl.wikipedia.org/wiki/Igor_II_Olegowicz\" target=\"_blank\" rel=\"noopener noreferrer\">św. Igor</a>, którego wspomina się 5 czerwca. Na Rusi Kijowskiej stanowi ślad obecności wikińskiej. W Polsce odbierane jako typowo „wschodnie”.", "Ireneusz": "<b>Ireneusz</b> (<a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>eirenaios</i> – „spokojny, pokojowy”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. W Polsce pojawiło się w XIX wieku.", "Ignacy": "<b>Ignacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o niepewnej do końca etymologii. Według najbardziej rozpowszechnionej teorii wywodzi się je od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> wyrazu <i>ignis</i>, oznaczającego „ogień”. Zachodzi jednak również podobieństwo między tym imieniem, a nazwą łacińskiego rodu <a href=\"https://pl.wikipedia.org/wiki/Egnacjusze\" target=\"_blank\" rel=\"noopener noreferrer\">Egnacjuszów</a> (<i>Egnatii</i>). Istnieją też hipotezy o <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruskim</a> pochodzeniu Ignacego.", "Ihor": "<b>Igor</b> – zaimportowane z Rosji <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>, wywodzące się z pierwotnego <b><a href=\"https://pl.wikipedia.org/wiki/Ingwar\" target=\"_blank\" rel=\"noopener noreferrer\">Ingwar</a></b> (<i>Ingvarr</i>). Imię to jest złożone z członów: <i>Ing-</i>, prawdopodobnie pochodzącego od imienia jednego z bogów germańskich, oraz <i>-war</i>, pochodzącego najprawdopodobniej od staro-wysoko-niemieckiego słowa <i>wart</i> – <i><b>stróż</b></i>, <i><b>pasterz</b></i>. Imię to nosił wielki książę kijowski i czernihowski z <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII</a> wieku <a href=\"https://pl.wikipedia.org/wiki/Igor_II_Olegowicz\" target=\"_blank\" rel=\"noopener noreferrer\">św. Igor</a>, którego wspomina się 5 czerwca. Na Rusi Kijowskiej stanowi ślad obecności wikińskiej. W Polsce odbierane jako typowo „wschodnie”.", "Iwo": "<b>Iwo</b>, <i>Iwon</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (ewentualnie celtyckiego). Wywodzi się najprawdopodobniej z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a> <i>iwa</i> oznaczającego „drzewo cisowe”, „łuk z cisowego drewna” lub <i><a href=\"https://pl.wikipedia.org/wiki/Wierzba\" target=\"_blank\" rel=\"noopener noreferrer\">wierzba</a></i>, ewentualnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_breto%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">bretońska</a> (<a href=\"https://pl.wikipedia.org/wiki/Iroszkoci\" target=\"_blank\" rel=\"noopener noreferrer\">iroszkocka</a>) forma imienia <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> będąca zapożyczeniem z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a> od <i>Ιωάννης</i>. Forma Iwon powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Iwo zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1206\" target=\"_blank\" rel=\"noopener noreferrer\">1206</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Iwo w 2017 r. zajmował 97. miejsce w grupie imion męskich.", "Izydor": "<b>Izydor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, utworzone przez <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">Greków</a> osiadłych w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnym Egipcie</a> po podboju Egiptu przez <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Wielkiego</a>. Grecy ci włączyli do swego <a href=\"https://pl.wikipedia.org/wiki/Panteon\" target=\"_blank\" rel=\"noopener noreferrer\">panteonu</a> boginię <a href=\"https://pl.wikipedia.org/wiki/Izyda\" target=\"_blank\" rel=\"noopener noreferrer\">Izydę</a> jako jedno z głównych <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bóstw</a>.", "Irakli": "<b>Irakli</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Ира́кли), właściwie <b>Iraklij Leonidowicz Pircchaława</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Ира́клий Леони́дович Пирцхала́ва; ur. <a href=\"https://pl.wikipedia.org/wiki/13_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">13 września</a> <a href=\"https://pl.wikipedia.org/wiki/1977\" target=\"_blank\" rel=\"noopener noreferrer\">1977</a> w <a href=\"https://pl.wikipedia.org/wiki/Moskwa\" target=\"_blank\" rel=\"noopener noreferrer\">Moskwie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">rosyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarz</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gruzja\" target=\"_blank\" rel=\"noopener noreferrer\">gruzińskiego</a>.", "Ibrahim": "<b>Ibrahim</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <i>إبراهيم</i>, <i>Ibrāhīm</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_arabskie\" target=\"_blank\" rel=\"noopener noreferrer\">imię arabskie</a>, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">starotestamentowego</a> <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>.", "Idzi": "<b>Idzi</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Jest spolszczeniem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <b>Aegidius</b>, „Egidiusz”, o źródłosłowie greckim. <i>Aigidios</i> był jednym z przydomków <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i nawiązywał do noszenia przez niego tarczy <a href=\"https://pl.wikipedia.org/wiki/Egida\" target=\"_blank\" rel=\"noopener noreferrer\">Egidy</a>.", "Islam": "Z islamu wywodzą się też inne religie abrahamiczne jak <a href=\"https://pl.wikipedia.org/wiki/Druzowie\" target=\"_blank\" rel=\"noopener noreferrer\">druzyzm</a> (XI wiek), <a href=\"https://pl.wikipedia.org/wiki/Jezydyzm\" target=\"_blank\" rel=\"noopener noreferrer\">jezydyzm</a> (XII wiek), <a href=\"https://pl.wikipedia.org/wiki/Babizm\" target=\"_blank\" rel=\"noopener noreferrer\">babizm</a> (XIX wiek) i potomny mu <a href=\"https://pl.wikipedia.org/wiki/Bahaizm\" target=\"_blank\" rel=\"noopener noreferrer\">bahaizm</a> (XIX wiek). Islam miał też wpływ na pojawienie się w XV wieku <a href=\"https://pl.wikipedia.org/wiki/Sikhizm\" target=\"_blank\" rel=\"noopener noreferrer\">sikhizmu</a>, niezaliczanego do grupy abrahamicznej.", "I": "<b>I</b> (<a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>i</b>) – dziewiąta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, dwunasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Oznacza zwykle w danym języku samogłoskę przednią wysoką, np. [<a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_przymkni%C4%99ta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">i</a>] lub [<a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_prawie_przymkni%C4%99ta_przednia_scentralizowana_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɪ</a>].", "Izrael": "<b>Izrael</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יִשְׂרָאֵל&#8206;, <i>Jisra’el</i>) – imię hebrajskie o niejasnym już dziś znaczeniu. Zgodnie z <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijną</a> przypowieścią, powstało z połączenia słów oznaczających „będzie się zmagał z Bogiem\" (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;לשרות&#8206;, <i>lisrot</i> – „zmagać się”, &#8207;אֵל‎&#8206;, <i>El</i> – „Bóg\"). Według tradycji po raz pierwszy nadano je patriarsze <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakubowi</a>, który po walce z <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">posłańcem Boga</a> lub samym <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Bogiem</a> usłyszał: „Odtąd nie będziesz nazywał się Jakub, ale Izrael, bo walczyłeś z Bogiem i z ludźmi i zwyciężyłeś” (<a href=\"https://biblia.deon.pl/otworz.php?skrot=Rdz%2032,29\" target=\"_blank\" rel=\"noopener noreferrer\">Rdz 32,29</a>).", "Imam": "<b>Imam</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> إمام, dosł. „przywódca”) – muzułmański przywódca religijny; w tradycyjnym znaczeniu – przewodniczący rytualnej modlitwy <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmańskiej</a>, czyli <a href=\"https://pl.wikipedia.org/wiki/Salat\" target=\"_blank\" rel=\"noopener noreferrer\">salatu</a>. W ogólności może to być osoba świecka bądź przełożony meczetu. Władca kraju również może być nazywany imamem.", "Izajasz": "<b>Izajasz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יְשַׁעְיָהוּ&#8206;, <i>Jeszajahu</i>, <i>Yesha'yahu</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> jest zbawieniem” lub „Jahwe zbaw”, ur. ok. <a href=\"https://pl.wikipedia.org/wiki/765_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">765</a>, zm. do <a href=\"https://pl.wikipedia.org/wiki/701_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">701 p.n.e.</a>) – jeden z największych <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroków</a> <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>. Jego proroctwa przedstawia <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Izajasza\" target=\"_blank\" rel=\"noopener noreferrer\">Księga Izajasza</a>.", "Imre": "<b>Emeryk</b>, Amalaryk, Amalryk – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze starogermańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Amalaryk\" target=\"_blank\" rel=\"noopener noreferrer\">Amalaryk</a>, oznaczającego „władca <a href=\"https://pl.wikipedia.org/wiki/Amalowie\" target=\"_blank\" rel=\"noopener noreferrer\">Amalów</a>” (Amalowie według gockiej legendy to ród królewski pochodzenia boskiego). Człon <i>amal</i> może także oznaczać „gorliwy” lub „dzielny, aktywny”. Emeryk może wywodzić się również z saksońskiego <i>Emmerich</i>, oznaczającego „zawsze bogaty”.", "Ildefons": "<b>Ildefons</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>hild</i> \"walka, potyczka\" i <i>funs </i> \"gotowy\", co mogło oznaczać \"gotowego do walki\". Patronem tego imienia jest św. Ildefons z <a href=\"https://pl.wikipedia.org/wiki/Toledo_(Hiszpania)\" target=\"_blank\" rel=\"noopener noreferrer\">Toledo</a>, zakonnik, biskup (<a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wiek</a>).", "Ikar": "Ojciec przestrzegł syna przed niebezpieczeństwem spowodowanym zbyt wysokim lotem. Ikar jednak wzbił się zbyt wysoko, a wtedy słońce roztopiło wosk, którym były złączone pióra. Chłopiec zginął, spadając do <a href=\"https://pl.wikipedia.org/wiki/Morze_Ikaryjskie\" target=\"_blank\" rel=\"noopener noreferrer\">Morza Ikaryjskiego</a>, którego nazwa według mitu pochodzi od jego imienia. Dedal krążył nad tym miejscem, dopóki ciało nie wypłynęło, a następnie pochował je na wyspie zwanej później <a href=\"https://pl.wikipedia.org/wiki/Ikaria\" target=\"_blank\" rel=\"noopener noreferrer\">Ikarią</a>. Według innej wersji mitu ciało przeniósł na wyspę Ikarię <a href=\"https://pl.wikipedia.org/wiki/Herakles\" target=\"_blank\" rel=\"noopener noreferrer\">Herakles</a>. Nie we wszystkich wersjach mitu o Dedalu i Ikarze występuje lot na spojonych woskiem skrzydłach: według innych Dedal wynalazł nie skrzydła, ale żagle, chcąc w ten sposób wyprzedzić flotę Minosa, zaś Ikar utonął spadając ze statku wskutek nieostrożnego obchodzenia się ze sterem.", "Innocenty": "<b>Innocenty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"niewinny, prawy\". Imię to zostało przybrane przez 13 <a href=\"https://pl.wikipedia.org/wiki/Poczet_papie%C5%BCy\" target=\"_blank\" rel=\"noopener noreferrer\">papieży</a> i jednego antypapieża.", "Ike": "<b>Indywidualne konto emerytalne (IKE)</b> – dobrowolna forma <a href=\"https://pl.wikipedia.org/wiki/Emerytura\" target=\"_blank\" rel=\"noopener noreferrer\">ubezpieczenia społecznego</a> w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a>, stanowiąca element tzw. <a href=\"https://pl.wikipedia.org/wiki/System_emerytalny_w_Polsce#Dodatkowe_formy_ubezpieczenia_emerytalnego\" target=\"_blank\" rel=\"noopener noreferrer\">III filaru emerytalnego</a>.", "Inge": "<b>Inge</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_p%C3%B3%C5%82nocnogerma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a> imię męskie, odpowiednik żeńskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Inga\" target=\"_blank\" rel=\"noopener noreferrer\">Inga</a>.", "Iwon": "<b>Iwo</b>, <i>Iwon</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (ewentualnie celtyckiego). Wywodzi się najprawdopodobniej z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a> <i>iwa</i> oznaczającego „drzewo cisowe”, „łuk z cisowego drewna” lub <i><a href=\"https://pl.wikipedia.org/wiki/Wierzba\" target=\"_blank\" rel=\"noopener noreferrer\">wierzba</a></i>, ewentualnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_breto%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">bretońska</a> (<a href=\"https://pl.wikipedia.org/wiki/Iroszkoci\" target=\"_blank\" rel=\"noopener noreferrer\">iroszkocka</a>) forma imienia <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> będąca zapożyczeniem z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a> od <i>Ιωάννης</i>. Forma Iwon powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Iwo zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1206\" target=\"_blank\" rel=\"noopener noreferrer\">1206</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Iwo w 2017 r. zajmował 97. miejsce w grupie imion męskich.", "Ingolf": "<b>Ingolf</b> – męskie imię <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a>, składające się z członów <i>Ing-</i> i <i>-wolf</i>. Według jednych badaczy pierwszy człon imienia, <i>Ing-</i>, pochodzi od germańskiego <i>Ingwa</i>, <i>Ingu</i>, co oznacza \"członek plemienia Ingweonów\", inne źródła podają, iż człon ten wywodzi się od imienia germańskiego boga, a kolejne wskazują, iż ów germański bóg był pierwotnie bogiem plemienia Ingweonów. Człon drugi imienia oznacza \"wilk\".", "Iwanow": "<b>Iwanow</b> – pierwsze lub drugie (po <a href=\"https://pl.wikipedia.org/wiki/Smirnow\" target=\"_blank\" rel=\"noopener noreferrer\">Smirnow</a>) wśród najpopularniejszych <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisk</a> <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">rosyjskich</a>. Występuje również poza Rosją w państwach takich jak <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukraina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białoruś</a>. Jest też jednym z częściej spotykanych nazwisk w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>. Pochodzi od wschodniej wersji imienia własnego Jan (Iwan).", "Ida": "<b>Ida</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a> o dyskusyjnej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a>, notowane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku w formach <i><b>Ida</b></i> i <i><b>Hida</b></i>, ze zdrobnieniami Idka, Idźka, Hidka. Stanowi formę skróconą od germańskich imion złożonych z pierwszym członem <i>Id-</i>, takich jak <b>Ideburga</b> bądź <b>Iduberga</b> (człon ów jest związany ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">stnord.</a> <i>idh</i> – „działalność”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">stang.</a> <i>idig</i> – „pilny”, lub też z pierwszym członem <i>Hid-</i> (<i>Hild-</i> – „walka, bitwa”; zanik <i>h</i> w nagłosie wynikałby z wpływów <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_roma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">romańskich</a>).", "Ika": "<b>Iga</b> – imię żeńskie. Usamodzielnione w czasach współczesnych zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Jadwiga\" target=\"_blank\" rel=\"noopener noreferrer\">Jadwiga</a>. Może być również zdrobnieniem imienia <a href=\"https://pl.wikipedia.org/wiki/Ignacja\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacja</a>.", "Isao": "<b>Isao</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;いさお, イサオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, bardzo popularne w erze <a href=\"https://pl.wikipedia.org/wiki/Sh%C5%8Dwa\" target=\"_blank\" rel=\"noopener noreferrer\">Shōwa</a>.", "Izasław": "<b>Izasław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>, nienotowane w źródłach staropolskich. Składa się z członów <i>Iza-</i> (od <i>изяти</i>, czyli „wziąć”) i -<i>sław</i> („sława”).", "Ingbert": "<b>Ingbert</b>, <b>Ingobert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Powstało ze starowysokoniem. <i>Ing(wio)</i> (imię germańskiego boga) i <i>beraht</i> (błyszczący, świecący). Imię to ma dwóch świętych patronów.", "Ingwar": "<b>Ingwar</b> (inaczej <a href=\"https://pl.wikipedia.org/wiki/Igor\" target=\"_blank\" rel=\"noopener noreferrer\">Igor</a>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> prawdopodobnie pochodzenia skandynawskiego (Ingwar). Pochodzi od słów <i>Ingwo</i> (bóstwo skandynawskie) i <i>wari</i> (stróż, obrońca). Obce formy: <a href=\"https://pl.wikipedia.org/wiki/Igor\" target=\"_blank\" rel=\"noopener noreferrer\">Igor</a> Ivar, Ingwar, Ingvar (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>).", "Izmael": "<a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Flawiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Józef Flawiusz</a> w dziele <i>Dawne dzieje Izraela</i> (ks. I rdz. 12, 4) wymienia imiona synów Izmaela: Nabajon, Kedar, <a href=\"https://pl.wikipedia.org/wiki/Abdeel\" target=\"_blank\" rel=\"noopener noreferrer\">Abdeel</a>, Masam, Masmas, Idumas, Masmes, Chodam, Teman, Jetur, Nafais, Kadmas. Założyli oni plemiona o nazwach pochodzących od swych imion, jako cały lud nazwali się Arabami.", "Ines": "<b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Icchak": "<b>Izaak</b> (<i>Icchak, Jic`chak</i>, <i>Icaak</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Wywodzi się od słowa יצחק oznaczającego „śmiech”, <i>jishak</i> („Bóg uśmiechnął się”). Imię <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a> ze składnikiem <i>isha</i>. Imię Izaak nosił <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">starotestamentowy</a> syn <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, brat <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Ismaela</a>, <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">patriarcha Izaak</a>.", "Imisław": "<b>Imisław</b>, <b>Jimisław</b>, <b>Himisław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, po raz pierwszy odnotowane w <a href=\"https://pl.wikipedia.org/wiki/1212\" target=\"_blank\" rel=\"noopener noreferrer\">1212</a> roku. Składa się z członów: <i>Imi-</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">prasł.</a> <i>*jęti</i>, w <a href=\"https://pl.wikipedia.org/wiki/Tryb_rozkazuj%C4%85cy\" target=\"_blank\" rel=\"noopener noreferrer\">trybie rozkazującym</a> <i>*jьmi</i> („jąć”, „rozpocząć”) i <i>-sław</i> („sława”). Nie ma odpowiedników w innych językach słowiańskich. Mogło oznaczać „ten, który zapoczątkowuje sławę”. Jako Himisław (z H-protetycznym) wystąpiło w XV wieku (1409)", "Izbor": "<b>Izbor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Iz-</i> („z”) i <i>-bor</i> („walczyć, zmagać się”). Mogło oznaczać „pochodzącego z walki”, „posiadającego sławę z walki” itp.", "Irydion": "<b>Irydion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_literackie\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia literackiego</a>, utworzone przez <a href=\"https://pl.wikipedia.org/wiki/Zygmunt_Krasi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Zygmunta Krasińskiego</a> na potrzeby <a href=\"https://pl.wikipedia.org/wiki/Irydion_(dramat)\" target=\"_blank\" rel=\"noopener noreferrer\">dramatu</a> o tym samym tytule. Pochodzi od imienia <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej</a> bogini <a href=\"https://pl.wikipedia.org/wiki/Iris_(c%C3%B3rka_Taumasa)\" target=\"_blank\" rel=\"noopener noreferrer\">Irydy</a> (Iris) oznaczającego <i>tęczę</i>.", "Issachar": "Był synem <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> i <a href=\"https://pl.wikipedia.org/wiki/Lea_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Lei</a>, od którego wywodzi się jedno z <a href=\"https://pl.wikipedia.org/wiki/Dwana%C5%9Bcie_Plemion_Izraela\" target=\"_blank\" rel=\"noopener noreferrer\">pokoleń Izraela</a>. Według tradycji miał dożyć 122 lat.", "Itsuki": "<b>Itsuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;いつき, イツキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone częściej przez mężczyzn niż przez kobiety. Jest używane także jako nazwisko.", "Isaj": "Jesse pochodził z pokolenia <a href=\"https://pl.wikipedia.org/wiki/Juda_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Judy</a>. Po mieczu był wnukiem <a href=\"https://pl.wikipedia.org/wiki/Booz\" target=\"_blank\" rel=\"noopener noreferrer\">Booza</a> i <a href=\"https://pl.wikipedia.org/wiki/Rut\" target=\"_blank\" rel=\"noopener noreferrer\">Rut</a>. Według 1 Krn 2,13-16 miał siedmiu synów – Eliaba, Abinadaba, Szimeę, Netaneela, Raddaja, Osema i Dawida – a także dwie córki, Seruję i Abigail, natomiast według 1 Sm 16,10n i 1 Sm 17,12 – ośmiu synów.", "Inna": "<b>Innocencja</b> – jeden z żeńskich odpowiedników <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Innocenty_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Innocenty</a>.", "Italiano": "<b>Język włoski</b> (wł. <em>lingua italiana</em>, <em>italiano</em> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">/</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_przymkni%C4%99ta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">i</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">t</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_podniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">j</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82przymkni%C4%99ta_tylna_zaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">o</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">/</a>) – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_roma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">język romański</a> objęty statusem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urz%C4%99dowy\" target=\"_blank\" rel=\"noopener noreferrer\">urzędowego</a> we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a>, <a href=\"https://pl.wikipedia.org/wiki/San_Marino\" target=\"_blank\" rel=\"noopener noreferrer\">San Marino</a>, <a href=\"https://pl.wikipedia.org/wiki/Watykan\" target=\"_blank\" rel=\"noopener noreferrer\">Watykanie</a> (obok <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>), <a href=\"https://pl.wikipedia.org/wiki/Szwajcaria\" target=\"_blank\" rel=\"noopener noreferrer\">Szwajcarii</a> (obok <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckiego</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_romansz\" target=\"_blank\" rel=\"noopener noreferrer\">romansz</a>) oraz na <a href=\"https://pl.wikipedia.org/wiki/Istria\" target=\"_blank\" rel=\"noopener noreferrer\">Istrii</a>, należącej do <a href=\"https://pl.wikipedia.org/wiki/Chorwacja\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwacji</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owenia\" target=\"_blank\" rel=\"noopener noreferrer\">Słowenii</a>. W pewnym stopniu używany również we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a> (zwłaszcza na <a href=\"https://pl.wikipedia.org/wiki/Korsyka\" target=\"_blank\" rel=\"noopener noreferrer\">Korsyce</a>) i na <a href=\"https://pl.wikipedia.org/wiki/Malta\" target=\"_blank\" rel=\"noopener noreferrer\">Malcie</a>. Można się nim także porozumieć w skupiskach <a href=\"https://pl.wikipedia.org/wiki/Migracja_ludno%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">emigracji</a> włoskiej w <a href=\"https://pl.wikipedia.org/wiki/Argentyna\" target=\"_blank\" rel=\"noopener noreferrer\">Argentynie</a>, <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a>, <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a> i <a href=\"https://pl.wikipedia.org/wiki/Tunezja\" target=\"_blank\" rel=\"noopener noreferrer\">Tunezji</a> oraz w pewnym niewielkim stopniu w <a href=\"https://pl.wikipedia.org/wiki/Erytrea\" target=\"_blank\" rel=\"noopener noreferrer\">Erytrei</a>, byłej <a href=\"https://pl.wikipedia.org/wiki/Kolonie_w%C5%82oskie\" target=\"_blank\" rel=\"noopener noreferrer\">kolonii włoskiej</a> (przez pewien czas używano go też w <a href=\"https://pl.wikipedia.org/wiki/Libia\" target=\"_blank\" rel=\"noopener noreferrer\">Libii</a> i <a href=\"https://pl.wikipedia.org/wiki/Somalia\" target=\"_blank\" rel=\"noopener noreferrer\">Somalii</a>, ale po wycofaniu się włoskich kolonialistów wyszedł tam z użycia). Włoski jest silnie zróżnicowany <a href=\"https://pl.wikipedia.org/wiki/Dialekt\" target=\"_blank\" rel=\"noopener noreferrer\">dialektalnie</a>, jego współczesna <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_standardowy\" target=\"_blank\" rel=\"noopener noreferrer\">forma standardowa</a> oparta jest na dialekcie <a href=\"https://pl.wikipedia.org/wiki/Toskania\" target=\"_blank\" rel=\"noopener noreferrer\">toskańskim</a>, znormalizowanym na przełomie XIII i XIV wieku przez <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego Alighieri</a> i wielu współczesnych mu twórców, takich jak <a href=\"https://pl.wikipedia.org/wiki/Francesco_Petrarca\" target=\"_blank\" rel=\"noopener noreferrer\">Francesco Petrarca</a> i <a href=\"https://pl.wikipedia.org/wiki/Giovanni_Boccaccio\" target=\"_blank\" rel=\"noopener noreferrer\">Giovanni Boccaccio</a>.", "Isamu": "<b>Isamu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;いさむ, イサム) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Ingrid": "<b>Ingryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od złożenia słów <i>Ing</i> – imienia jednego z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_nordycka\" target=\"_blank\" rel=\"noopener noreferrer\">bogów nordyckich</a> – i <i>fríðr</i>, w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskim</a> oznaczającego „piękno”. Patronką imienia jest szwedzka dominikanka bł. <a href=\"https://pl.wikipedia.org/wiki/Ingryda_Szwedzka\" target=\"_blank\" rel=\"noopener noreferrer\">Ingryda Szwedzka</a>.", "Ina": "<b>Ina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię żeńskie</a>, funkcjonujące jako samodzielne imię.", "Iwona": "<b>Iwona</b> – imię żeńskie o pochodzeniu germańskim bądź celtyckim, odpowiednik męskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Iwo\" target=\"_blank\" rel=\"noopener noreferrer\">Iwo</a>.", "Irena": "<b>Irena</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;εἰρήνη [eirene] – pokój) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Męską formą tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Ireneusz\" target=\"_blank\" rel=\"noopener noreferrer\">Ireneusz</a>.", "Izabela": "<b>Izabela</b> – spolszczenie imienia <i>Isabel</i>, tj. albo <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznego</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oksyta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">oksytańskiego</a>, następnie rozpowszechnionego w <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a> i szerzej w <a href=\"https://pl.wikipedia.org/wiki/Europa_Zachodnia\" target=\"_blank\" rel=\"noopener noreferrer\">Europie Zachodniej</a> odpowiednika imienia <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbieta</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> אלישבע (Wj 6,23) <i>eliszewa</i> („mój Bóg przysięgą”), albo pochodzi ono od imienia <a href=\"https://pl.wikipedia.org/wiki/Izebel\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnej królowej <i>Jezabel</i></a>, której imię oznacza w hebrajskim „wywyższona przez <a href=\"https://pl.wikipedia.org/wiki/Baal\" target=\"_blank\" rel=\"noopener noreferrer\">Baala</a>”.", "Ilona": "<b>Ilona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C4%99gierski\" target=\"_blank\" rel=\"noopener noreferrer\">węgierska</a> forma imienia <a href=\"https://pl.wikipedia.org/wiki/Helena_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Helena</a>.", "Iga": "<b>Iga</b> – imię żeńskie. Usamodzielnione w czasach współczesnych zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Jadwiga\" target=\"_blank\" rel=\"noopener noreferrer\">Jadwiga</a>. Może być również zdrobnieniem imienia <a href=\"https://pl.wikipedia.org/wiki/Ignacja\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacja</a>.", "Izabella": "<b>Izabela</b> – spolszczenie imienia <i>Isabel</i>, tj. albo <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznego</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oksyta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">oksytańskiego</a>, następnie rozpowszechnionego w <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a> i szerzej w <a href=\"https://pl.wikipedia.org/wiki/Europa_Zachodnia\" target=\"_blank\" rel=\"noopener noreferrer\">Europie Zachodniej</a> odpowiednika imienia <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbieta</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> אלישבע (Wj 6,23) <i>eliszewa</i> („mój Bóg przysięgą”), albo pochodzi ono od imienia <a href=\"https://pl.wikipedia.org/wiki/Izebel\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnej królowej <i>Jezabel</i></a>, której imię oznacza w hebrajskim „wywyższona przez <a href=\"https://pl.wikipedia.org/wiki/Baal\" target=\"_blank\" rel=\"noopener noreferrer\">Baala</a>”.", "Inga": "Wywodzi się od zdrobnienia grupy imion, także męskich, znanych w kulturach <a href=\"https://pl.wikipedia.org/wiki/Germania\" target=\"_blank\" rel=\"noopener noreferrer\">germańskich</a> i <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskich</a> rozpoczynających się od <i>Ing-</i>, imienia jednego z <a href=\"https://pl.wikipedia.org/wiki/Normanowie\" target=\"_blank\" rel=\"noopener noreferrer\">normandzkich</a> bóstw.", "Irmina": "<b>Irmina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od zdrobnienia grupy imion rozpoczynających się na <i>irm</i> – od <i>irmen</i>, co oznacza „czczony, szanowany”.", "Irmgarda": "<b>Ermegarda</b>, <b>Irmegarda</b>, <b>Irmgarda</b>, Ermengarda, Irmengarda – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, którego pierwszy człon to <i>Ermen–</i>, od germ. <i>ermana</i> („wielki, wszechogarniający” – imię <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82b%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">półboga</a> germańskiego), występujący w różnych imionach także w innych odmiankach, np. <i>Ermina</i> i <i><a href=\"https://pl.wikipedia.org/wiki/Irmina\" target=\"_blank\" rel=\"noopener noreferrer\">Irmina</a></i> (ta ostatnia wykształcona z poprzedniej, z podwyższoną artykulacją pierwszej samogłoski pod wpływem <i>–i–</i> w następnej sylabie). Człon drugi imienia wiąże się z germ. <i>gardaz</i> – „ogrodzenie, płot”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">goc.</a> <i>garda</i> – „pleciony płot, obora”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>gardo</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>garto</i> – „ogród” i należy go rozumieć jako „ogrodzoną posiadłość”.", "Irma": "<b>Irma</b> – imię żeńskie pochodzenia germańskiego.", "Idalia": "<b>Idalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Afrodyta\" target=\"_blank\" rel=\"noopener noreferrer\">Afrodytę</a>, boginię miłości, nazywano przydomkiem „Idalia” od gór Idalion (Idalium) na <a href=\"https://pl.wikipedia.org/wiki/Cypr_(wyspa)\" target=\"_blank\" rel=\"noopener noreferrer\">Cyprze</a>, gdzie znajdowała się jej świątynia.", "Ingeborga": "<b>Ingeborga</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od złożenia słów <i>Ing</i> – imię jednego z <a href=\"https://pl.wikipedia.org/wiki/Kraje_nordyckie\" target=\"_blank\" rel=\"noopener noreferrer\">nordyckich</a> bogów i <i>borg</i> oznaczającego „forteca”, „twierdza”.", "Izolda": "<b>Izolda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> lub <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się najprawdopodobniej z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_walijski\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiego</a> <i>Essylt</i> oznaczającego „piękna”. Według legendy nosiła to imię irlandzka księżniczka, kochanka <a href=\"https://pl.wikipedia.org/wiki/Tristan\" target=\"_blank\" rel=\"noopener noreferrer\">Tristana</a>, zaręczona królowi <a href=\"https://pl.wikipedia.org/wiki/Kornwalia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornwalii</a> <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Markowi</a>. Możliwe jednak, że imię pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a> <i>isan</i> „żelazo” i <i>waltan</i> „rządzić, panować”.", "Ismena": "<b>Ismena</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰσμήνη) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od postaci <a href=\"https://pl.wikipedia.org/wiki/Ismena_(c%C3%B3rka_Edypa)\" target=\"_blank\" rel=\"noopener noreferrer\">Ismeny</a>, postaci z greckiej mitologii, córki <a href=\"https://pl.wikipedia.org/wiki/Edyp\" target=\"_blank\" rel=\"noopener noreferrer\">Edypa</a> i <a href=\"https://pl.wikipedia.org/wiki/Jokasta\" target=\"_blank\" rel=\"noopener noreferrer\">Jokasty</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;ισμη (isme), co oznacza <i>wiedzę</i>.", "Ingrida": "<b>Ingryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od złożenia słów <i>Ing</i> – imienia jednego z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_nordycka\" target=\"_blank\" rel=\"noopener noreferrer\">bogów nordyckich</a> – i <i>fríðr</i>, w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskim</a> oznaczającego „piękno”. Patronką imienia jest szwedzka dominikanka bł. <a href=\"https://pl.wikipedia.org/wiki/Ingryda_Szwedzka\" target=\"_blank\" rel=\"noopener noreferrer\">Ingryda Szwedzka</a>.", "Iwetta": "<b>Iweta</b>, <i>Iwetta</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Iwo\" target=\"_blank\" rel=\"noopener noreferrer\">Iwo</a>, którego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Iwona\" target=\"_blank\" rel=\"noopener noreferrer\">Iwona</a>.", "Iweta": "<b>Iweta</b>, <i>Iwetta</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Iwo\" target=\"_blank\" rel=\"noopener noreferrer\">Iwo</a>, którego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Iwona\" target=\"_blank\" rel=\"noopener noreferrer\">Iwona</a>.", "Izydora": "<b>Izydora</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „dar Izydy” i pochodzi od imienia <a href=\"https://pl.wikipedia.org/wiki/Izyda\" target=\"_blank\" rel=\"noopener noreferrer\">Izydy</a>, egipskiej bogini.", "Ilza": "<b>Ilza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Pochodzi ze zdrobniałej formy niemieckiej odmiany imienia <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbieta</a> - <i>Elizabeth</i> - <i>Ilse</i>.", "Ingryda": "<b>Ingryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od złożenia słów <i>Ing</i> – imienia jednego z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_nordycka\" target=\"_blank\" rel=\"noopener noreferrer\">bogów nordyckich</a> – i <i>fríðr</i>, w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskim</a> oznaczającego „piękno”. Patronką imienia jest szwedzka dominikanka bł. <a href=\"https://pl.wikipedia.org/wiki/Ingryda_Szwedzka\" target=\"_blank\" rel=\"noopener noreferrer\">Ingryda Szwedzka</a>.", "Iwa": "<b>Iwona</b> – imię żeńskie o pochodzeniu germańskim bądź celtyckim, odpowiednik męskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Iwo\" target=\"_blank\" rel=\"noopener noreferrer\">Iwo</a>.", "India": "<b>India</b> – imię żeńskie, wywodzące się od nazwy kraju (<a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indie</a>) i pośrednio od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indus</a>. Ma negatywną opinię Rady Języka Polskiego.", "Iraida": "<b>Raisa</b> – rosyjskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, występujące także w Polsce, przede wszystkim na obszarze, na którym zamieszkują mniejszości wyznające prawosławie (ponad 60% Rais mieszka w <a href=\"https://pl.wikipedia.org/wiki/Wojew%C3%B3dztwo_bia%C5%82ostockie_(1975%E2%80%931998)\" target=\"_blank\" rel=\"noopener noreferrer\">Białostockiem</a>), którego etymologia nie jest jasna. Podaje się różne warianty pochodzenia imienia: od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <i>radia</i> – „lekka”; od gr. <i>reistos</i>, <i>radios</i> – „lekkomyślna, beztroska, niefrasobliwa” lub też przypisuje się jej znaczenie „wypoczęta”. Istnieją również przesłanki do utożsamienia tego imienia z imieniem Iraida (pod imieniem <i><b>Raisa (Iraida)</b></i> wymieniana jest ważna święta prawosławna), którego greckim wariantem jest Irais – por. Izis i <a href=\"https://pl.wikipedia.org/wiki/Izyda\" target=\"_blank\" rel=\"noopener noreferrer\">Izyda</a>. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">Ros.</a> Iraida pochodzi zaś od gr. <i>hērōis</i>, w <a href=\"https://pl.wikipedia.org/wiki/Dope%C5%82niacz_(przypadek)\" target=\"_blank\" rel=\"noopener noreferrer\">dop.</a> <i>hērōidos</i> – „heroina” (tj. „bohaterka”). Sposób utworzenia Raisy od heroiny byłby zatem analogiczny do przekształcenia, w wyniku którego z imienia Herodion powstał rosyjski wariant Rodion.", "Izaura": "<b>Izaura</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego osobę pochodzącą z <a href=\"https://pl.wikipedia.org/wiki/Izauria\" target=\"_blank\" rel=\"noopener noreferrer\">Izaurii</a> (region <a href=\"https://pl.wikipedia.org/wiki/Azja_Mniejsza\" target=\"_blank\" rel=\"noopener noreferrer\">Azji Mniejszej</a>). Popularne w państwach hiszpańsko- i portugalskojęzycznych. Do języka polskiego przedostało się za pośrednictwem popularnego w latach 80. XX w. <a href=\"https://pl.wikipedia.org/wiki/Brazylia\" target=\"_blank\" rel=\"noopener noreferrer\">brazylijskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Serial_telewizyjny\" target=\"_blank\" rel=\"noopener noreferrer\">serialu telewizyjnego</a> <i><a href=\"https://pl.wikipedia.org/wiki/Niewolnica_Isaura_(telenowela_1976)\" target=\"_blank\" rel=\"noopener noreferrer\">Niewolnica Isaura</a></i>.", "Imelda": "<b>Imelda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z elementów <i>irmen</i> – \"cały\" i <i>hild</i> – \"walka\". Istnieją trzy <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ogos%C5%82awiony\" target=\"_blank\" rel=\"noopener noreferrer\">błogosławione</a> patronki tego imienia:", "Ignacja": "<b>Ignacja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ignacy\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacy</a>, które posiada nieustaloną do końca etymologię. Według najbardziej rozpowszechnionej teorii wywodzi się je od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> wyrazu <i>ignis</i>, oznaczającego „ogień”. Zachodzi jednak również podobieństwo między tym imieniem a nazwą łacińskiego rodu <a href=\"https://pl.wikipedia.org/wiki/Egnacjusze\" target=\"_blank\" rel=\"noopener noreferrer\">Egnacjuszów</a> (<i>Egnatii</i>). Istnieją też hipotezy o <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruskim</a> pochodzeniu Ignacego.", "Isaura": "<b>Izaura</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego osobę pochodzącą z <a href=\"https://pl.wikipedia.org/wiki/Izauria\" target=\"_blank\" rel=\"noopener noreferrer\">Izaurii</a> (region <a href=\"https://pl.wikipedia.org/wiki/Azja_Mniejsza\" target=\"_blank\" rel=\"noopener noreferrer\">Azji Mniejszej</a>). Popularne w państwach hiszpańsko- i portugalskojęzycznych. Do języka polskiego przedostało się za pośrednictwem popularnego w latach 80. XX w. <a href=\"https://pl.wikipedia.org/wiki/Brazylia\" target=\"_blank\" rel=\"noopener noreferrer\">brazylijskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Serial_telewizyjny\" target=\"_blank\" rel=\"noopener noreferrer\">serialu telewizyjnego</a> <i><a href=\"https://pl.wikipedia.org/wiki/Niewolnica_Isaura_(telenowela_1976)\" target=\"_blank\" rel=\"noopener noreferrer\">Niewolnica Isaura</a></i>.", "Isadora": "<b>Izydora</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „dar Izydy” i pochodzi od imienia <a href=\"https://pl.wikipedia.org/wiki/Izyda\" target=\"_blank\" rel=\"noopener noreferrer\">Izydy</a>, egipskiej bogini.", "Imogen": "Według badaczy z <a href=\"https://pl.wikipedia.org/wiki/Uniwersytet_Oksfordzki\" target=\"_blank\" rel=\"noopener noreferrer\">Uniwersytetu w Oksfordzie</a> prawidłowa pisownia jej imienia to <i>Innogen</i>, zaś zamiana dwóch liter <i>n</i> na <i>m</i> nastąpiła na skutek błędu edytorskiego w jednym ze wczesnych wydań tego utworu.", "Innocenta": "<b>Innocenta</b>, <b>Innocentyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Innocenty_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Innocenty</a>", "Iryda": "<b>Iryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (Ιρις tęcza). Imię to w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> nosiła <a href=\"https://pl.wikipedia.org/wiki/Iris_(c%C3%B3rka_Taumasa)\" target=\"_blank\" rel=\"noopener noreferrer\">Iris</a>, bogini uosabiająca tęczę.", "Imisława": "<b>Imisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Składa się z członu <i>Imi-</i> („jąć”, „rozpocząć”) i <i>-sława</i> („sława”). Mogło oznaczać „ta, która zapoczątkowuje sławę”. W źródłach polskich poświadczone w XIV wieku (1398 rok).", "Izumi": "<b>Izumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;いずみ, いづみ, イズミ, イヅミ, 泉) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone częściej przez kobiety niż przez mężczyzn. Jest używane jako imię, nazwisko lub nazwa miejsca.", "Ikuko": "<b>Ikuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;郁子) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>. Znak <i>iku</i> (郁) oznacza „aromat” lub „postęp kulturowy”, znak <i>ko</i> (子) dosłownie oznacza „dziecko” i tradycyjnie występuje w imionach żeńskich.", "Imogena": "Według badaczy z <a href=\"https://pl.wikipedia.org/wiki/Uniwersytet_Oksfordzki\" target=\"_blank\" rel=\"noopener noreferrer\">Uniwersytetu w Oksfordzie</a> prawidłowa pisownia jej imienia to <i>Innogen</i>, zaś zamiana dwóch liter <i>n</i> na <i>m</i> nastąpiła na skutek błędu edytorskiego w jednym ze wczesnych wydań tego utworu.", "Iben": "<b>Jan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωάννης od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> rdzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יחנ&#8206; – łaska) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> יוחנן (<i>Johanan</i>) oznacza „Jahwe jest łaskawy”. Według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostoł</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Ewangelista\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Ewangelista</a>. Zostało ono przejęte najpierw do greki, a potem do łaciny. Rozpowszechniło się we wszystkich krajach <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskich</a>.", "Ingarda": "<b>Ingarda</b> – żeńskie imię <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a>, notowane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecza</a> w formach <i>Ingardis</i> i <i>Hingardis</i>. Według jednych badaczy pierwszy człon imienia, <i>Ing-</i>, pochodzi od germańskiego <i>Ingwa</i>, <i>Ingu</i>, co oznacza \"członek plemienia Ingweonów\", inne źródła podają, iż człon ten wywodzi się od imienia germańskiego boga, a kolejne wskazują, iż ów germański bóg był pierwotnie bogiem plemienia Ingweonów. Człon drugi imienia wiąże się z germ. <i>gardaz</i> — \"ogrodzenie, płot\", <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">goc.</a> <i>garda</i> — \"pleciony płot, obora\", <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>gardo</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>garto</i> — \"ogród\" i należy go rozumieć jako \"ogrodzoną posiadłość\".", "Irenka": "Nazwa strugi pochodzi od dawnej nazwy miasta Dęblin, które wcześniej nazywało się Irena. Nazwa miała na celu odróżnienie wsi Irena od osady Dęblin, która skupiała się przy <a href=\"https://pl.wikipedia.org/wiki/D%C4%99blin_(stacja_kolejowa)\" target=\"_blank\" rel=\"noopener noreferrer\">stacji kolejowej Dęblin</a> – dużego <a href=\"https://pl.wikipedia.org/wiki/W%C4%99ze%C5%82_kolejowy\" target=\"_blank\" rel=\"noopener noreferrer\">węzła kolejowego</a> na linii <a href=\"https://pl.wikipedia.org/wiki/Warszawa\" target=\"_blank\" rel=\"noopener noreferrer\">Warszawa</a>-<a href=\"https://pl.wikipedia.org/wiki/Lublin\" target=\"_blank\" rel=\"noopener noreferrer\">Lublin</a> i <a href=\"https://pl.wikipedia.org/wiki/D%C4%99blin\" target=\"_blank\" rel=\"noopener noreferrer\">Dęblin</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81uk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Łuków</a>. Na terenie miasta Dęblin struga jest uregulowana i oczyszczana.", "Ilayla": "<b>Leila</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;ليلى&#8206;) – używane na całym świecie arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">języków semickich</a>, od <a href=\"https://pl.wikipedia.org/wiki/Alternacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">rdzenia trójspółgłoskowego</a>: <a href=\"https://pl.wikipedia.org/wiki/L%C4%81m\" target=\"_blank\" rel=\"noopener noreferrer\"><b>L</b></a>-<a href=\"https://pl.wikipedia.org/wiki/Y%C4%81%CA%BE\" target=\"_blank\" rel=\"noopener noreferrer\"><b>J</b></a>-<a href=\"https://pl.wikipedia.org/wiki/L%C4%81m\" target=\"_blank\" rel=\"noopener noreferrer\"><b>L</b></a> (&#8207;ليل&#8206;, rdzeń wspólny z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> <i><a href=\"https://pl.wikipedia.org/wiki/Lilith\" target=\"_blank\" rel=\"noopener noreferrer\">Lilith</a></i>) i oznaczające „noc”; z czasem nabrało znaczenia „urodzona w nocy”, „ciemnowłosa piękność” lub „ciemna piękność”, w innych językach także jako <i>Lejla</i>, <i>Leyla</i>, <i>Layla</i>, <i>Laila</i>.", "Ildefonsa": "<b>Ildefonsa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>hild</i> \"walka, potyczka\" i <i>funs </i> \"gotowy\", co mogło oznaczać \"gotową do walki\". Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Ildefons_z_Toledo\" target=\"_blank\" rel=\"noopener noreferrer\">Ildefons z Toledo</a>, zakonnik, biskup (<a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wiek</a>).", "Iroha": "<b>Iroha</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;いろは, 伊呂波) – (1) skrót od <b>Iroha-uta</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;いろは歌, 伊呂波歌), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">japoński</a> <a href=\"https://pl.wikipedia.org/wiki/Literatura_japo%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">wiersz</a> pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Heian\" target=\"_blank\" rel=\"noopener noreferrer\">okresu Heian</a> (794–1185), pierwszy znany jego zapis pochodzi z 1079 roku, jest on <a href=\"https://pl.wikipedia.org/wiki/Pangram\" target=\"_blank\" rel=\"noopener noreferrer\">pangramem</a> zawierającym każdy znak <a href=\"https://pl.wikipedia.org/wiki/Kana_(pismo)\" target=\"_blank\" rel=\"noopener noreferrer\">kana</a> tylko jeden raz; (2) tradycyjny japoński <a href=\"https://pl.wikipedia.org/wiki/Sylabariusz\" target=\"_blank\" rel=\"noopener noreferrer\">sylabariusz</a>; (3) podstawy, ABC czegoś; (4) <a href=\"https://pl.wikipedia.org/wiki/Sylaba\" target=\"_blank\" rel=\"noopener noreferrer\">sylaby</a> służące do oznaczania kolejności, podobnie jak w <a href=\"https://pl.wikipedia.org/wiki/Alfabet\" target=\"_blank\" rel=\"noopener noreferrer\">alfabecie</a>, zamiast: a, b, c, d, według <i>iroha</i>: i, ro, ha, ni, ho itd..", "Illuminata": "<b>Illuminata</b> (od łacińskiego <i>cognomen Illuminatus</i> – oświecony) – żeńskie imię pochodzące z języka <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Męska forma imienia to <i>Illuminat</i>. Imię to występuje również w formie: <i>Iluminata</i>. Greckim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a>, a w językach słowiańskich <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awietlana\" target=\"_blank\" rel=\"noopener noreferrer\">Świetlana</a>. Podaje się dwie święte tego imienia, w tym <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Illuminata\" target=\"_blank\" rel=\"noopener noreferrer\">Świętą Illuminatę</a> z IV wieku.", "Irmtruda": "Imię to notowane było w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> w formach <i><b>Ermentrudis</b></i>, <i><b>Hermentrudis</b></i>, <i><b>Hermtrudis</b></i>, obecnie także m.in. jako <i>Irmentrauda</i>, <i>Irmtraud</i>, <i>Irmtrauda</i>, <i>Irmtraut</i>, <i>Irmtrauta</i>, <i>Irmtruda</i>. Możliwe średniowieczne zdrobnienia i formy pochodne to <a href=\"https://pl.wikipedia.org/wiki/Ema_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Emma</a>, Imma, Ermusza, Imka, Jimka.", "Idunn": "<b>Idun</b>, <b>Idunn</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronord.</a> <i>Iðunn</i>) – bogini <a href=\"https://pl.wikipedia.org/wiki/Wiosna\" target=\"_blank\" rel=\"noopener noreferrer\">wiosny</a> w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_nordycka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii skandynawskiej</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Bragi\" target=\"_blank\" rel=\"noopener noreferrer\">Bragiego</a>, córka karła <a href=\"https://pl.wikipedia.org/wiki/Iwaldi\" target=\"_blank\" rel=\"noopener noreferrer\">Iwaldiego</a>. Jej imię znaczyło dosłownie <i>odnawiająca</i>, <i>odmładzająca</i>. Opiekowała się koszem ze złotymi jabłkami młodości, który zawsze był pełny. Pozwalały one zachować młodość każdemu, kto je spożył. Idun podawała je tylko bogom na ucztach w <a href=\"https://pl.wikipedia.org/wiki/Asgard\" target=\"_blank\" rel=\"noopener noreferrer\">Asgardzie</a>. Bogowie dotkliwie odczuli stratę złotych jabłek, kiedy Idunn i jej owoce porwał olbrzym Thjazi. Bogowie natychmiast zaczęli się starzeć. <a href=\"https://pl.wikipedia.org/wiki/Loki\" target=\"_blank\" rel=\"noopener noreferrer\">Loki</a>, będący pośrednim sprawcą porwania, zdołał uwolnić Idunn i przywieźć do Asgardu wraz z owocami."};
